package com.bank.api.ws.cxf;

import com.bank.api.ws.BankingTransactionServiceImpl;
import org.apache.cxf.Bus;
import org.apache.cxf.bus.spring.SpringBusFactory;
import org.apache.cxf.endpoint.Endpoint;
import org.apache.cxf.frontend.ServerFactoryBean;
import org.apache.cxf.interceptor.LoggingInInterceptor;
import org.apache.cxf.interceptor.LoggingOutInterceptor;
import org.apache.cxf.jaxws.JaxWsServerFactoryBean;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;
import org.apache.wss4j.dom.handler.WSHandlerConstants;

import java.util.HashMap;
import java.util.Map;
import java.util.Properties;

public final class CxfBankingServicePublisher {

    private CxfBankingServicePublisher() {}

    public static void main(String[] args) {
        String address = System.getProperty("bank.ws.address", "http://0.0.0.0:8080/bank/transactions");
        String keystorePath = System.getProperty("bank.ws.keystore", "server-keystore.jks");
        String keystorePassword = System.getProperty("bank.ws.keystore.password", "changeit");
        String keyAlias = System.getProperty("bank.ws.key.alias", "server");
        String keyPassword = System.getProperty("bank.ws.key.password", keystorePassword);
        String truststorePath = System.getProperty("bank.ws.truststore", "server-truststore.jks");
        String truststorePassword = System.getProperty("bank.ws.truststore.password", "changeit");

        Bus bus = new SpringBusFactory().createBus();
        org.apache.cxf.BusFactory.setDefaultBus(bus);

        JaxWsServerFactoryBean sf = new JaxWsServerFactoryBean();
        sf.setBus(bus);
        sf.setAddress(address);
        sf.setServiceBean(new BankingTransactionServiceImpl());

        sf.getInInterceptors().add(new LoggingInInterceptor());
        sf.getOutInterceptors().add(new LoggingOutInterceptor());

        WSS4JInInterceptor wssIn = new WSS4JInInterceptor(inProps(truststorePath, truststorePassword));
        sf.getInInterceptors().add(wssIn);
        sf.getInInterceptors().add(new SignedElementsExtractorInInterceptor());

        WSS4JOutInterceptor wssOut = new WSS4JOutInterceptor(outProps(keystorePath, keystorePassword, keyAlias, keyPassword));
        sf.getOutInterceptors().add(wssOut);

        sf.create();
        System.out.println("BankingTransactionService published at " + address);
    }

    private static Map<String, Object> inProps(String truststorePath, String truststorePassword) {
        Map<String, Object> props = new HashMap<>();
        props.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        props.put(WSHandlerConstants.SIG_PROP_REF_ID, "cxfTrustCrypto");
        props.put("cxfTrustCrypto", cryptoProps(truststorePath, truststorePassword));
        props.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");
        props.put(WSHandlerConstants.SIG_ALGO, "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256");
        props.put(WSHandlerConstants.DIGEST_ALGO, "http://www.w3.org/2001/04/xmlenc#sha256");
        props.put(WSHandlerConstants.REQUIRE_TIMESTAMP, "true");
        props.put(WSHandlerConstants.TTL_TIMESTAMP, "300");
        return props;
    }

    private static Map<String, Object> outProps(String keystorePath, String keystorePassword, String keyAlias, String keyPassword) {
        Map<String, Object> props = new HashMap<>();
        props.put(WSHandlerConstants.ACTION, WSHandlerConstants.TIMESTAMP + " " + WSHandlerConstants.SIGNATURE);
        props.put(WSHandlerConstants.USER, keyAlias);
        props.put(WSHandlerConstants.PW_CALLBACK_REF, (org.apache.wss4j.common.ext.WSPasswordCallback pc) -> {});
        props.put(WSHandlerConstants.SIG_PROP_REF_ID, "cxfKeyCrypto");
        props.put("cxfKeyCrypto", cryptoProps(keystorePath, keystorePassword));
        props.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");
        props.put(WSHandlerConstants.SIG_ALGO, "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256");
        props.put(WSHandlerConstants.DIGEST_ALGO, "http://www.w3.org/2001/04/xmlenc#sha256");
        props.put(WSHandlerConstants.SIGNATURE_PARTS,
                "{Element}{http://schemas.xmlsoap.org/soap/envelope/}Body;" +
                "{Element}{http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd}Timestamp;");
        props.put(WSHandlerConstants.PASSWORD_TYPE, "PasswordText");
        props.put(WSHandlerConstants.PW_CALLBACK_CLASS, "com.bank.api.ws.cxf.StaticPasswordCallback");
        props.put("bank.key.password", keyPassword);
        return props;
    }

    private static Properties cryptoProps(String keystorePath, String password) {
        Properties p = new Properties();
        p.put("org.apache.wss4j.crypto.provider", "org.apache.wss4j.common.crypto.Merlin");
        p.put("org.apache.wss4j.crypto.merlin.keystore.type", "jks");
        p.put("org.apache.wss4j.crypto.merlin.keystore.password", password);
        p.put("org.apache.wss4j.crypto.merlin.keystore.file", keystorePath);
        return p;
    }
}

package com.bank.api.ws.cxf;

import org.apache.wss4j.common.ext.WSPasswordCallback;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;

public class StaticPasswordCallback implements CallbackHandler {
    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        String pwd = System.getProperty("bank.ws.key.password");
        if (pwd == null) pwd = System.getProperty("bank.key.password");
        if (pwd == null) pwd = "changeit";

        for (Callback cb : callbacks) {
            if (cb instanceof WSPasswordCallback) {
                ((WSPasswordCallback) cb).setPassword(pwd);
            }
        }
    }
}